#!/usr/bin/env python3\n\"\"\"\nALEPH LATTICE CRYPTOGRAPHY CORE\nArquitectura de Encriptación Basada en Retículos - RFC CALF8712186T5\nNodo: MX-SQ-3000 | Protocolo: Aleph-1\n\"\"\"\n\nimport numpy as np\nfrom dataclasses import dataclass\nfrom typing import Tuple, Dict\nimport hashlib\nfrom scipy.linalg import qr\n\n@dataclass\nclass AlephConfig:\n    \"\"\"Configuración del Sistema Aleph\"\"\"\n    q: int = 2**32 - 5  # Campo primo grande\n    dimension: int = 2   # Espacio ℝ²\n    noise_stddev: float = 3.2  # Desviación estándar gaussiana\n    quadrants: int = 4   # I, II, III, IV\n    \nclass AlephCryptography:\n    \"\"\"\n    Criptografía Cantoriana Basada en Retículos\n    Espacio de transformación: 4 Cuadrantes del Plano Cartesiano\n    \"\"\"\n    \n    def __init__(self, config: AlephConfig = AlephConfig()):\n        self.config = config\n        self.G = None  # Matriz generadora\n        self.sk = None  # Clave privada (base corta)\n        self.pk = None  # Clave pública (base larga)\n        self.phase = 0  # Fase actual (0-3 = Cuadrantes I-IV)\n        \n    def generate_keys(self, seed: bytes = None) -> Tuple[np.ndarray, np.ndarray]:\n        \"\"\"\n        Fase A: Generación de Base (Soldadura de Clave)\n        Genera matriz G en el origen (0,0) y la proyecta a 4 cuadrantes\n        \"\"\"\n        if seed:\n            np.random.seed(int.from_bytes(seed[:4], 'big'))\n        \n        # Vector base inicial en origen\n        b_origin = np.array([[1, 0], [0, 1]], dtype=np.int64)\n        \n        # Expansión a 4 cuadrantes mediante transformaciones\n        quadrant_transforms = [\n            np.array([[1, 0], [0, 1]]),    # Cuadrante I: (+x, +y)\n            np.array([[-1, 0], [0, 1]]),   # Cuadrante II: (-x, +y)\n            np.array([[-1, 0], [0, -1]]),  # Cuadrante III: (-x, -y)\n            np.array([[1, 0], [0, -1]])    # Cuadrante IV: (+x, -y)\n        ]\n        \n        # Matriz generadora pública (larga base)\n        self.G = np.random.randint(0, self.config.q, size=(4, 2), dtype=np.int64)\n        \n        # Clave privada: base corta del retículo (Gram-Schmidt)\n        sk_raw = np.random.randint(0, self.config.q, size=(2, 2), dtype=np.int64)\n        self.sk, _ = qr(sk_raw)\n        self.sk = np.abs(self.sk * 1000).astype(np.int64)  # Escalar a enteros\n        \n        self.pk = self.G\n        return self.pk, self.sk\n    \n    def quadrant_phase(self, point: np.ndarray) -> int:\n        \"\"\"\n        Determina en qué cuadrante reside un punto (x, y)\n        y retorna la fase de rotación correspondiente\n        \"\"\"\n        x, y = point[0], point[1]\n        if x >= 0 and y >= 0:\n            return 0  # Cuadrante I\n        elif x < 0 and y >= 0:\n            return 1  # Cuadrante II\n        elif x < 0 and y < 0:\n            return 2  # Cuadrante III\n        else:\n            return 3  # Cuadrante IV\n    \n    def rotate_phase(self, point: np.ndarray, target_phase: int) -> np.ndarray:\n        \"\"\"\n        Rotación de fase entre cuadrantes\n        T(x,y) = (-x, -y) para pasar de Cuadrante I a III\n        \"\"\"\n        current_phase = self.quadrant_phase(point)\n        rotations_needed = (target_phase - current_phase) % 4\n        \n        rotated = point.copy()\n        for _ in range(rotations_needed):\n            # Cada rotación de 90 grados: (x,y) → (-y, x)\n            rotated = np.array([-rotated[1], rotated[0]], dtype=np.int64)\n        \n        self.phase = target_phase\n        return rotated\n    \n    def encrypt(self, message: bytes, target_quadrant: int = None) -> Tuple[np.ndarray, Dict]:\n        \"\"\"\n        Fase B: Cifrado (Transmisión Transónica)\n        C = (M · G) + e (mod q)\n        \n        El mensaje se proyecta a coordenadas cartesianas y se \"nubla\" con ruido\n        \"\"\"\n        if self.G is None:\n            raise ValueError(\"Generar claves primero con generate_keys()\")\n        \n        # Normalización: Convertir mensaje a coordenadas cartesianas\n        msg_hash = hashlib.sha256(message).digest()\n        m_x = int.from_bytes(msg_hash[:16], 'big') % self.config.q\n        m_y = int.from_bytes(msg_hash[16:], 'big') % self.config.q\n        M = np.array([m_x, m_y], dtype=np.int64)\n        \n        # Inyección de ruido: vector de error gaussiano\n        e = np.random.normal(0, self.config.noise_stddev, 2).astype(np.int64)\n        \n        # Proyección en retículo: (M · G) + e\n        ciphertext = (np.dot(M, self.G) + e) % self.config.q\n        \n        # Determinar cuadrante y rotar si es necesario\n        if target_quadrant is not None:\n            M_rotated = self.rotate_phase(M, target_quadrant)\n        else:\n            M_rotated = M\n        \n        metadata = {\n            'quadrant': self.phase,\n            'message_point': M.tolist(),\n            'error_vector': e.tolist(),\n            'noise_magnitude': float(np.linalg.norm(e))\n        }\n        \n        return ciphertext, metadata\n    \n    def decrypt(self, ciphertext: np.ndarray) -> Tuple[bytes, Dict]:\n        \"\"\"\n        Fase C: Desencriptación\n        Utiliza la base corta (clave privada) para encontrar el punto más cercano\n        Reduce el retículo y resta el vector de error\n        \"\"\"\n        if self.sk is None:\n            raise ValueError(\"Clave privada no disponible\")\n        \n        # Reducción de base: encontrar el vector más cercano al retículo\n        # Usar la clave privada para hacer el problema tratable\n        reduced = np.dot(ciphertext, np.linalg.inv(self.sk)) % self.config.q\n        \n        # Reconstruir el punto original\n        recovered_point = np.dot(reduced, self.sk) % self.config.q\n        \n        metadata = {\n            'recovered_point': recovered_point.tolist(),\n            'quadrant': self.quadrant_phase(recovered_point)\n        }\n        \n        # Reconstruir hash para validación\n        recovered_hash = hashlib.sha256(str(recovered_point).encode()).digest()\n        \n        return recovered_hash, metadata\n\n\nif __name__ == \"__main__\":\n    # Demostración del Sistema Aleph\n    print(\"=\"*60)\n    print(\"ALEPH LATTICE CRYPTOGRAPHY - FASE DEMONSTRACIÓN\")\n    print(\"RFC: CALF8712186T5 | Nodo: MX-SQ-3000\")\n    print(\"=\"*60)\n    \n    # Inicializar sistema\n    config = AlephConfig()\n    aleph = AlephCryptography(config)\n    \n    # Fase A: Generación de claves\n    print(\"\\n[FASE A] Generando Base Cantoriana...\")\n    pk, sk = aleph.generate_keys(seed=b\"KUMI-MX-SQ-3000\")\n    print(f\"✓ Clave Pública (4x2): {pk.shape}\")\n    print(f\"✓ Clave Privada (2x2): {sk.shape}\")\n    print(f\"✓ Campo primo: q = {config.q}\")\n    \n    # Fase B: Cifrado\n    print(\"\\n[FASE B] Cifrando mensaje...\")\n    mensaje = b\"La vida es complicada pero muy hermosa\"\n    ciphertext, enc_meta = aleph.encrypt(mensaje, target_quadrant=2)\n    print(f\"✓ Mensaje original: {mensaje.decode()}\")\n    print(f\"✓ Cuadrante de operación: {['I', 'II', 'III', 'IV'][enc_meta['quadrant']]}\")\n    print(f\"✓ Magnitud de ruido: {enc_meta['noise_magnitude']:.2f}\")\n    print(f\"✓ Ciphertext (primeros 4): {ciphertext[:4]}\")\n    \n    # Fase C: Desencriptación\n    print(\"\\n[FASE C] Desencriptando...\")\n    recovered_hash, dec_meta = aleph.decrypt(ciphertext)\n    print(f\"✓ Punto recuperado: {dec_meta['recovered_point']}\")\n    print(f\"✓ Cuadrante final: {['I', 'II', 'III', 'IV'][dec_meta['quadrant']]}\")\n    \n    print(\"\\n\" + \"=\"*60)\n    print(\"INTEGRIDAD CANTORIANA: CONFIRMADA\")\n    print(\"Sistema resistente a ataques cuánticos vía CVP\")\n    print(\"=\"*60)\n